   288→absl::optional<uint32_t> SPIFFEValidator::daysUntilFirstCertExpires() const {
   289→  if (ca_certs_.empty()) {
   290→    return absl::make_optional(std::numeric_limits<uint32_t>::max());
   291→  }
   292→  absl::optional<uint32_t> ret = absl::make_optional(std::numeric_limits<uint32_t>::max());
   293→  for (auto& cert : ca_certs_) {
   294→    const absl::optional<uint32_t> tmp = Utility::getDaysUntilExpiration(cert.get(), time_source_);
   295→    if (!tmp.has_value()) {
   296→      return absl::nullopt;
   297→    } else if (tmp.value() < ret.value()) {
   298→      ret = tmp;
   299→    }
   300→  }
   301→  return ret;
   302→}
