   304→Envoy::Ssl::CertificateDetailsPtr SPIFFEValidator::getCaCertInformation() const {
   305→  if (ca_certs_.empty()) {
   306→    return nullptr;
   307→  }
   308→  // TODO(mathetake): With the current interface, we cannot pass the multiple cert information.
   309→  // So temporarily we return the first CA's info here.
   310→  return Utility::certificateDetails(ca_certs_[0].get(), getCaFileName(), time_source_);
   311→};
