   260→  // SPIFFE cert validation algorithm succeeded, which requires exactly one URI SAN in the leaf
   261→  // cert.
   262→  ASSERT(san_names != nullptr,
   263→         "san_names should have at least one name after SPIFFE cert validation");
   264→
