    69→bool Utility::dnsNameMatch(absl::string_view dns_name, absl::string_view pattern) {
    70→  // A-label ACE prefix https://www.rfc-editor.org/rfc/rfc5890#section-2.3.2.5.
    71→  constexpr absl::string_view ACE_prefix = "xn--";
    72→  const std::string lower_case_dns_name = absl::AsciiStrToLower(dns_name);
    73→  const std::string lower_case_pattern = absl::AsciiStrToLower(pattern);
    74→  if (lower_case_dns_name == lower_case_pattern) {
    75→    return true;
    76→  }
    77→
    78→  std::vector<absl::string_view> split_pattern =
    79→      absl::StrSplit(lower_case_pattern, absl::MaxSplits('.', 1));
    80→  std::vector<absl::string_view> split_dns_name =
    81→      absl::StrSplit(lower_case_dns_name, absl::MaxSplits('.', 1));
    82→
    83→  // dns name and pattern should contain more than 1 label to match.
    84→  if (split_pattern.size() < 2 || split_dns_name.size() < 2) {
    85→    return false;
    86→  }
    87→  // Only the left-most label in the pattern contains wildcard '*' and is not an A-label.
    88→  if ((split_pattern[0].find('*') != absl::string_view::npos) &&
    89→      (split_pattern[1].find('*') == absl::string_view::npos) &&
    90→      (!absl::StartsWith(split_pattern[0], ACE_prefix))) {
    91→    return (split_dns_name[1] == split_pattern[1]) &&
    92→           labelWildcardMatch(split_dns_name[0], split_pattern[0]);
    93→  }
    94→
    95→  return false;
    96→}
