   193→std::string Utility::generalNameAsString(const GENERAL_NAME* general_name) {
   194→  std::string san;
   195→  ASN1_STRING* str = nullptr;
   196→  switch (general_name->type) {
   197→  case GEN_DNS:
   198→    str = general_name->d.dNSName;
   199→    san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(str)), ASN1_STRING_length(str));
   200→    break;
   201→  case GEN_URI:
   202→    str = general_name->d.uniformResourceIdentifier;
   203→    san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(str)), ASN1_STRING_length(str));
   204→    break;
   205→  case GEN_EMAIL:
   206→    str = general_name->d.rfc822Name;
