   208→    break;
   209→  case GEN_IPADD: {
   210→    if (general_name->d.ip->length == 4) {
   211→      sockaddr_in sin;
   212→      memset(&sin, 0, sizeof(sin));
   213→      sin.sin_port = 0;
   214→      sin.sin_family = AF_INET;
   215→      safeMemcpyUnsafeSrc(&sin.sin_addr, general_name->d.ip->data);
   216→      Network::Address::Ipv4Instance addr(&sin);
   217→      san = addr.ip()->addressAsString();
   218→    } else if (general_name->d.ip->length == 16) {
   219→      sockaddr_in6 sin6;
   220→      memset(&sin6, 0, sizeof(sin6));
   221→      sin6.sin6_port = 0;
   222→      sin6.sin6_family = AF_INET6;
   223→      safeMemcpyUnsafeSrc(&sin6.sin6_addr, general_name->d.ip->data);
   224→      Network::Address::Ipv6Instance addr(sin6);
   225→      san = addr.ip()->addressAsString();
   226→    }
   227→    break;
   228→  }
   229→  case GEN_OTHERNAME: {
   230→    ASN1_TYPE* value = general_name->d.otherName->value;
   231→    if (value == nullptr) {
   232→      break;
   233→    }
   234→    switch (value->type) {
   235→    case V_ASN1_NULL:
   236→      break;
   237→    case V_ASN1_BOOLEAN:
   238→      san = value->value.boolean ? "true" : "false";
