   241→    case V_ASN1_INTEGER: {
   242→      BIGNUM san_bn;
   243→      BN_init(&san_bn);
   244→      value->type == V_ASN1_ENUMERATED ? ASN1_ENUMERATED_to_BN(value->value.enumerated, &san_bn)
