   258→        break;
   259→      }
   260→      san.assign(tmp_obj);
   261→      break;
   262→    }
   263→    case V_ASN1_BIT_STRING: {
   264→      ASN1_BIT_STRING* tmp_str = value->value.bit_string;
   265→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   266→                 ASN1_STRING_length(tmp_str));
   267→      break;
   268→    }
   269→    case V_ASN1_OCTET_STRING: {
   270→      ASN1_OCTET_STRING* tmp_str = value->value.octet_string;
   271→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   272→                 ASN1_STRING_length(tmp_str));
   273→      break;
   274→    }
   275→    case V_ASN1_PRINTABLESTRING: {
   276→      ASN1_PRINTABLESTRING* tmp_str = value->value.printablestring;
   277→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
