   371→absl::optional<uint32_t> Utility::getDaysUntilExpiration(const X509* cert,
   372→                                                         TimeSource& time_source) {
   373→  if (cert == nullptr) {
   374→    return absl::make_optional(std::numeric_limits<uint32_t>::max());
   375→  }
   376→  int days, seconds;
   377→  if (ASN1_TIME_diff(&days, &seconds, currentASN1Time(time_source).get(),
   378→                     X509_get0_notAfter(cert))) {
   379→    if (days >= 0 && seconds >= 0) {
   380→      return absl::make_optional(days);
   381→    }
   382→  }
   383→  return absl::nullopt;
   384→}
