   216→      Network::Address::Ipv4Instance addr(&sin);
   217→      san = addr.ip()->addressAsString();
   218→    } else if (general_name->d.ip->length == 16) {
   219→      sockaddr_in6 sin6;
   220→      memset(&sin6, 0, sizeof(sin6));
   221→      sin6.sin6_port = 0;
   222→      sin6.sin6_family = AF_INET6;
   223→      safeMemcpyUnsafeSrc(&sin6.sin6_addr, general_name->d.ip->data);
   224→      Network::Address::Ipv6Instance addr(sin6);
   225→      san = addr.ip()->addressAsString();
   226→    }
   227→    break;
   228→  }
   229→  case GEN_OTHERNAME: {
   230→    ASN1_TYPE* value = general_name->d.otherName->value;
   231→    if (value == nullptr) {
   232→      break;
   233→    }
   234→    switch (value->type) {
   235→    case V_ASN1_NULL:
   236→      break;
   237→    case V_ASN1_BOOLEAN:
   238→      san = value->value.boolean ? "true" : "false";
   239→      break;
   240→    case V_ASN1_ENUMERATED:
   241→    case V_ASN1_INTEGER: {
   242→      BIGNUM san_bn;
   243→      BN_init(&san_bn);
   244→      value->type == V_ASN1_ENUMERATED ? ASN1_ENUMERATED_to_BN(value->value.enumerated, &san_bn)
   245→                                       : ASN1_INTEGER_to_BN(value->value.integer, &san_bn);
   246→      char* san_char = BN_bn2dec(&san_bn);
   247→      BN_free(&san_bn);
   248→      if (san_char != nullptr) {
   249→        san.assign(san_char);
   250→        OPENSSL_free(san_char);
   251→      }
   252→      break;
   253→    }
   254→    case V_ASN1_OBJECT: {
   255→      char tmp_obj[256]; // OID Max length
   256→      int obj_len = OBJ_obj2txt(tmp_obj, 256, value->value.object, 1);
   257→      if (obj_len > 256 || obj_len < 0) {
   258→        break;
   259→      }
   260→      san.assign(tmp_obj);
   261→      break;
   262→    }
   263→    case V_ASN1_BIT_STRING: {
   264→      ASN1_BIT_STRING* tmp_str = value->value.bit_string;
   265→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   266→                 ASN1_STRING_length(tmp_str));
   267→      break;
   268→    }
   269→    case V_ASN1_OCTET_STRING: {
   270→      ASN1_OCTET_STRING* tmp_str = value->value.octet_string;
   271→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   272→                 ASN1_STRING_length(tmp_str));
   273→      break;
   274→    }
   275→    case V_ASN1_PRINTABLESTRING: {
   276→      ASN1_PRINTABLESTRING* tmp_str = value->value.printablestring;
   277→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   278→                 ASN1_STRING_length(tmp_str));
   279→      break;
   280→    }
   281→    case V_ASN1_T61STRING: {
   282→      ASN1_T61STRING* tmp_str = value->value.t61string;
   283→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   284→                 ASN1_STRING_length(tmp_str));
   285→      break;
   286→    }
   287→    case V_ASN1_IA5STRING: {
   288→      ASN1_IA5STRING* tmp_str = value->value.ia5string;
   289→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   290→                 ASN1_STRING_length(tmp_str));
   291→      break;
   292→    }
   293→    case V_ASN1_GENERALSTRING: {
   294→      ASN1_GENERALSTRING* tmp_str = value->value.generalstring;
   295→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   296→                 ASN1_STRING_length(tmp_str));
   297→      break;
   298→    }
   299→    case V_ASN1_BMPSTRING: {
   300→      // `ASN1_BMPSTRING` is encoded using `UCS-4`, which needs conversion to UTF-8.
   301→      unsigned char* tmp = nullptr;
   302→      if (ASN1_STRING_to_UTF8(&tmp, value->value.bmpstring) < 0) {
   303→        break;
   304→      }
   305→      san.assign(reinterpret_cast<const char*>(tmp));
   306→      OPENSSL_free(tmp);
   307→      break;
   308→    }
   309→    case V_ASN1_UNIVERSALSTRING: {
   310→      // `ASN1_UNIVERSALSTRING` is encoded using `UCS-4`, which needs conversion to UTF-8.
   311→      unsigned char* tmp = nullptr;
   312→      if (ASN1_STRING_to_UTF8(&tmp, value->value.universalstring) < 0) {
   313→        break;
   314→      }
   315→      san.assign(reinterpret_cast<const char*>(tmp));
   316→      OPENSSL_free(tmp);
   317→      break;
   318→    }
   319→    case V_ASN1_UTCTIME: {
   320→      ASN1_UTCTIME* tmp_str = value->value.utctime;
   321→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   322→                 ASN1_STRING_length(tmp_str));
   323→      break;
   324→    }
   325→    case V_ASN1_GENERALIZEDTIME: {
   326→      ASN1_GENERALIZEDTIME* tmp_str = value->value.generalizedtime;
   327→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   328→                 ASN1_STRING_length(tmp_str));
   329→      break;
   330→    }
   331→    case V_ASN1_VISIBLESTRING: {
   332→      ASN1_VISIBLESTRING* tmp_str = value->value.visiblestring;
   333→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   334→                 ASN1_STRING_length(tmp_str));
   335→      break;
   336→    }
   337→    case V_ASN1_UTF8STRING: {
   338→      ASN1_UTF8STRING* tmp_str = value->value.utf8string;
   339→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   340→                 ASN1_STRING_length(tmp_str));
   341→      break;
   342→    }
   343→    case V_ASN1_SET: {
   344→      ASN1_STRING* tmp_str = value->value.set;
   345→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   346→                 ASN1_STRING_length(tmp_str));
   347→      break;
   348→    }
   349→    case V_ASN1_SEQUENCE: {
   350→      ASN1_STRING* tmp_str = value->value.sequence;
   351→      san.assign(reinterpret_cast<const char*>(ASN1_STRING_data(tmp_str)),
   352→                 ASN1_STRING_length(tmp_str));
   353→      break;
   354→    }
   355→    default:
   356→      break;
   357→    }
   358→  }
   359→  }
   360→  return san;
   361→}
   362→
   363→std::string Utility::getIssuerFromCertificate(X509& cert) {
   364→  return getRFC2253NameFromCertificate(cert, CertName::Issuer);
   365→}
   366→
   367→std::string Utility::getSubjectFromCertificate(X509& cert) {
   368→  return getRFC2253NameFromCertificate(cert, CertName::Subject);
   369→}
   370→
   371→absl::optional<uint32_t> Utility::getDaysUntilExpiration(const X509* cert,
   372→                                                         TimeSource& time_source) {
   373→  if (cert == nullptr) {
   374→    return absl::make_optional(std::numeric_limits<uint32_t>::max());
   375→  }
   376→  int days, seconds;
   377→  if (ASN1_TIME_diff(&days, &seconds, currentASN1Time(time_source).get(),
   378→                     X509_get0_notAfter(cert))) {
   379→    if (days >= 0 && seconds >= 0) {
   380→      return absl::make_optional(days);
   381→    }
   382→  }
   383→  return absl::nullopt;
   384→}
   385→
   386→absl::string_view Utility::getCertificateExtensionValue(X509& cert,
   387→                                                        absl::string_view extension_name) {
   388→  bssl::UniquePtr<ASN1_OBJECT> oid(
   389→      OBJ_txt2obj(std::string(extension_name).c_str(), 1 /* don't search names */));
   390→  if (oid == nullptr) {
   391→    return {};
   392→  }
   393→
   394→  int pos = X509_get_ext_by_OBJ(&cert, oid.get(), -1);
   395→  if (pos < 0) {
   396→    return {};
   397→  }
   398→
   399→  X509_EXTENSION* extension = X509_get_ext(&cert, pos);
   400→  if (extension == nullptr) {
   401→    return {};
   402→  }
   403→
   404→  const ASN1_OCTET_STRING* octet_string = X509_EXTENSION_get_data(extension);
   405→  RELEASE_ASSERT(octet_string != nullptr, "");
   406→
   407→  // Return the entire DER-encoded value for this extension. Correct decoding depends on
   408→  // knowledge of the expected structure of the extension's value.
   409→  const unsigned char* octet_string_data = ASN1_STRING_get0_data(octet_string);
   410→  const int octet_string_length = ASN1_STRING_length(octet_string);
   411→
   412→  return {reinterpret_cast<const char*>(octet_string_data),
   413→          static_cast<absl::string_view::size_type>(octet_string_length)};
   414→}
   415→
   416→SystemTime Utility::getValidFrom(const X509& cert) {
   417→  int days, seconds;
   418→  int rc = ASN1_TIME_diff(&days, &seconds, &epochASN1Time(), X509_get0_notBefore(&cert));
   419→  ASSERT(rc == 1);
   420→  // Casting to <time_t (64bit)> to prevent multiplication overflow when certificate valid-from date
   421→  // beyond 2038-01-19T03:14:08Z.
   422→  return std::chrono::system_clock::from_time_t(static_cast<time_t>(days) * 24 * 60 * 60 + seconds);
   423→}
   424→
   425→SystemTime Utility::getExpirationTime(const X509& cert) {
   426→  int days, seconds;
   427→  int rc = ASN1_TIME_diff(&days, &seconds, &epochASN1Time(), X509_get0_notAfter(&cert));
   428→  ASSERT(rc == 1);
   429→  // Casting to <time_t (64bit)> to prevent multiplication overflow when certificate not-after date
   430→  // beyond 2038-01-19T03:14:08Z.
   431→  return std::chrono::system_clock::from_time_t(static_cast<time_t>(days) * 24 * 60 * 60 + seconds);
   432→}
