   434→absl::optional<std::string> Utility::getLastCryptoError() {
   435→  auto err = ERR_get_error();
   436→
   437→  if (err != 0) {
   438→    char errbuf[256];
   439→
   440→    ERR_error_string_n(err, errbuf, sizeof(errbuf));
   441→    return std::string(errbuf);
   442→  }
   443→
   444→  return absl::nullopt;
