    53→bool Utility::labelWildcardMatch(absl::string_view dns_label, absl::string_view pattern) {
    54→  constexpr char glob = '*';
    55→  // Check the special case of a single * pattern, as it's common.
    56→  if (pattern.size() == 1 && pattern[0] == glob) {
    57→    return true;
