   108→std::string getRFC2253NameFromCertificate(X509& cert, CertName desired_name) {
   109→  bssl::UniquePtr<BIO> buf(BIO_new(BIO_s_mem()));
   110→  RELEASE_ASSERT(buf != nullptr, "");
   111→
   112→  X509_NAME* name = nullptr;
   113→  switch (desired_name) {
   114→  case CertName::Issuer:
   115→    name = X509_get_issuer_name(&cert);
   116→    break;
   117→  case CertName::Subject:
   118→    name = X509_get_subject_name(&cert);
   119→    break;
   120→  }
   121→
   122→  // flags=XN_FLAG_RFC2253 is the documented parameter for single-line output in RFC 2253 format.
   123→  // Example from the RFC:
   124→  //   * Single value per Relative Distinguished Name (RDN): CN=Steve Kille,O=Isode Limited,C=GB
   125→  //   * Multivalue output in first RDN: OU=Sales+CN=J. Smith,O=Widget Inc.,C=US
   126→  //   * Quoted comma in Organization: CN=L. Eagle,O=Sue\, Grabbit and Runn,C=GB
   127→  X509_NAME_print_ex(buf.get(), name, 0 /* indent */, XN_FLAG_RFC2253);
   128→
   129→  const uint8_t* data;
   130→  size_t data_len;
   131→  int rc = BIO_mem_contents(buf.get(), &data, &data_len);
   132→  ASSERT(rc == 1);
   133→  return {reinterpret_cast<const char*>(data), data_len};
