   408→void ContextImpl::keylogCallback(const SSL* ssl, const char* line) {
   409→  ASSERT(ssl != nullptr);
   410→  auto callbacks =
   411→      static_cast<Network::TransportSocketCallbacks*>(SSL_get_ex_data(ssl, sslSocketIndex()));
   412→  auto ctx = static_cast<ContextImpl*>(SSL_CTX_get_app_data(SSL_get_SSL_CTX(ssl)));
   413→  ASSERT(callbacks != nullptr);
   414→  ASSERT(ctx != nullptr);
   415→
   416→  if ((ctx->tls_keylog_local_.getIpListSize() == 0 ||
   417→       ctx->tls_keylog_local_.contains(
   418→           *(callbacks->connection().connectionInfoProvider().localAddress()))) &&
   419→      (ctx->tls_keylog_remote_.getIpListSize() == 0 ||
   420→       ctx->tls_keylog_remote_.contains(
   421→           *(callbacks->connection().connectionInfoProvider().remoteAddress())))) {
   422→    ctx->tls_keylog_file_->write(absl::StrCat(line, "\n"));
   423→  }
   424→}
