   434→std::vector<uint8_t> ContextImpl::parseAlpnProtocols(const std::string& alpn_protocols,
   435→                                                     absl::Status& parse_status) {
   436→  if (alpn_protocols.empty()) {
   437→    return {};
   438→  }
   439→
   440→  if (alpn_protocols.size() >= 65535) {
   441→    parse_status = absl::InvalidArgumentError("Invalid ALPN protocol string");
   442→    return {};
   443→  }
   444→
   445→  std::vector<uint8_t> out(alpn_protocols.size() + 1);
   446→  size_t start = 0;
   447→  for (size_t i = 0; i <= alpn_protocols.size(); i++) {
   448→    if (i == alpn_protocols.size() || alpn_protocols[i] == ',') {
   449→      if (i - start > 255) {
   450→        parse_status = absl::InvalidArgumentError("Invalid ALPN protocol string");
   451→        return {};
   452→      }
   453→
   454→      out[start] = i - start;
   455→      start = i + 1;
   456→    } else {
   457→      out[i + 1] = alpn_protocols[i];
   458→    }
   459→  }
   460→
   461→  return out;
   462→}
