   604→absl::optional<uint32_t> ContextImpl::daysUntilFirstCertExpires() const {
   605→  absl::optional<uint32_t> daysUntilExpiration = cert_validator_->daysUntilFirstCertExpires();
   606→  if (!daysUntilExpiration.has_value()) {
   607→    return absl::nullopt;
   608→  }
   609→  for (auto& ctx : tls_contexts_) {
   610→    const absl::optional<uint32_t> tmp =
   611→        Utility::getDaysUntilExpiration(ctx.cert_chain_.get(), factory_context_.timeSource());
   612→    if (!tmp.has_value()) {
   613→      return absl::nullopt;
   614→    }
   615→    daysUntilExpiration = std::min<uint32_t>(tmp.value(), daysUntilExpiration.value());
   616→  }
   617→  return daysUntilExpiration;
   618→}
   619→
   620→absl::optional<uint64_t> ContextImpl::secondsUntilFirstOcspResponseExpires() const {
   621→  absl::optional<uint64_t> secs_until_expiration;
   622→  for (auto& ctx : tls_contexts_) {
   623→    if (ctx.ocsp_response_) {
   624→      uint64_t next_expiration = ctx.ocsp_response_->secondsUntilExpiration();
   625→      secs_until_expiration = std::min<uint64_t>(
   626→          next_expiration, secs_until_expiration.value_or(std::numeric_limits<uint64_t>::max()));
   627→    }
   628→  }
   629→
   630→  return secs_until_expiration;
   631→}
