   636→
   637→std::vector<Envoy::Ssl::CertificateDetailsPtr> ContextImpl::getCertChainInformation() const {
   638→  std::vector<Envoy::Ssl::CertificateDetailsPtr> cert_details;
   639→  for (const auto& ctx : tls_contexts_) {
   640→    if (ctx.cert_chain_ == nullptr) {
   641→      continue;
   642→    }
   643→
   644→    auto detail = Utility::certificateDetails(ctx.cert_chain_.get(), ctx.getCertChainFileName(),
   645→                                              factory_context_.timeSource());
   646→    auto ocsp_resp = ctx.ocsp_response_.get();
   647→    if (ocsp_resp) {
   648→      auto* ocsp_details = detail->mutable_ocsp_details();
   649→      ProtobufWkt::Timestamp* valid_from = ocsp_details->mutable_valid_from();
   650→      TimestampUtil::systemClockToTimestamp(ocsp_resp->getThisUpdate(), *valid_from);
   651→      ProtobufWkt::Timestamp* expiration = ocsp_details->mutable_expiration();
   652→      TimestampUtil::systemClockToTimestamp(ocsp_resp->getNextUpdate(), *expiration);
   653→    }
   654→    cert_details.push_back(std::move(detail));
   655→  }
   656→  return cert_details;
   657→}
