   659→bool ContextImpl::parseAndSetAlpn(const std::vector<std::string>& alpn, SSL& ssl,
   660→                                  absl::Status& parse_status) {
   661→  std::vector<uint8_t> parsed_alpn = parseAlpnProtocols(absl::StrJoin(alpn, ","), parse_status);
   662→  if (!parse_status.ok()) {
   663→    return false;
   664→  }
   665→  if (!parsed_alpn.empty()) {
   666→    const int rc = SSL_set_alpn_protos(&ssl, parsed_alpn.data(), parsed_alpn.size());
   667→    // This should only if memory allocation fails, e.g. OOM.
   668→    RELEASE_ASSERT(rc == 0, Utility::getLastCryptoError().value_or(""));
   669→    return true;
   670→  }
   671→
   672→  return false;
   673→}
   674→
   675→ValidationResults ContextImpl::customVerifyCertChainForQuic(
   676→    STACK_OF(X509)& cert_chain, Ssl::ValidateResultCallbackPtr callback, bool is_server,
   677→    const Network::TransportSocketOptionsConstSharedPtr& transport_socket_options,
   678→    const CertValidator::ExtraValidationContext& validation_context, const std::string& host_name) {
   679→  ASSERT(!tls_contexts_.empty());
   680→  // It doesn't matter which SSL context is used, because they share the same cert validation
   681→  // config.
   682→  SSL_CTX* ssl_ctx = tls_contexts_[0].ssl_ctx_.get();
   683→  if (SSL_CTX_get_verify_mode(ssl_ctx) == SSL_VERIFY_NONE) {
   684→    // Skip validation if the TLS is configured SSL_VERIFY_NONE.
   685→    return {ValidationResults::ValidationStatus::Successful,
   686→            Envoy::Ssl::ClientValidationStatus::NotValidated, absl::nullopt, absl::nullopt};
   687→  }
   688→  ValidationResults result =
   689→      cert_validator_->doVerifyCertChain(cert_chain, std::move(callback), transport_socket_options,
   690→                                         *ssl_ctx, validation_context, is_server, host_name);
   691→  return result;
   692→}
