   699→
   700→bool TlsContext::isCipherEnabled(uint16_t cipher_id, uint16_t client_version) {
   701→  const SSL_CIPHER* c = SSL_get_cipher_by_value(cipher_id);
   702→  if (c == nullptr) {
   703→    return false;
   704→  }
   705→  // Skip TLS 1.2 only ciphersuites unless the client supports it.
   706→  if (SSL_CIPHER_get_min_version(c) > client_version) {
   707→    return false;
   708→  }
   709→  if (SSL_CIPHER_get_auth_nid(c) != NID_auth_ecdsa) {
   710→    return false;
   711→  }
   712→  for (const SSL_CIPHER* our_c : SSL_CTX_get_ciphers(ssl_ctx_.get())) {
   713→    if (SSL_CIPHER_get_id(our_c) == SSL_CIPHER_get_id(c)) {
   714→      return true;
   715→    }
   716→  }
   717→  return false;
   718→}
   719→
   720→absl::Status TlsContext::loadCertificateChain(const std::string& data,
   721→                                              const std::string& data_path) {
   722→  cert_chain_file_path_ = data_path;
   723→  bssl::UniquePtr<BIO> bio(BIO_new_mem_buf(const_cast<char*>(data.data()), data.size()));
   724→  RELEASE_ASSERT(bio != nullptr, "");
   725→  cert_chain_.reset(PEM_read_bio_X509_AUX(bio.get(), nullptr, nullptr, nullptr));
   726→  if (cert_chain_ == nullptr || !SSL_CTX_use_certificate(ssl_ctx_.get(), cert_chain_.get())) {
   727→    logSslErrorChain();
   728→    return absl::InvalidArgumentError(
   729→        absl::StrCat("Failed to load certificate chain from ", cert_chain_file_path_));
   730→  }
   731→  // Read rest of the certificate chain.
   732→  while (true) {
   733→    bssl::UniquePtr<X509> cert(PEM_read_bio_X509(bio.get(), nullptr, nullptr, nullptr));
   734→    if (cert == nullptr) {
   735→      break;
   736→    }
   737→    if (!SSL_CTX_add_extra_chain_cert(ssl_ctx_.get(), cert.get())) {
   738→      return absl::InvalidArgumentError(
   739→          absl::StrCat("Failed to load certificate chain from ", cert_chain_file_path_));
   740→    }
   741→    // SSL_CTX_add_extra_chain_cert() takes ownership.
   742→    cert.release();
   743→  }
   744→  // Check for EOF.
   745→  const uint32_t err = ERR_peek_last_error();
   746→  if (ERR_GET_LIB(err) == ERR_LIB_PEM && ERR_GET_REASON(err) == PEM_R_NO_START_LINE) {
   747→    ERR_clear_error();
   748→  } else {
   749→    return absl::InvalidArgumentError(
   750→        absl::StrCat("Failed to load certificate chain from ", cert_chain_file_path_));
   751→  }
   752→  return absl::OkStatus();
   753→}
