   199→      const auto& tls_certificate = tls_certificates[i].get();
   200→      if (!tls_certificate.pkcs12().empty()) {
   201→        creation_status = ctx.loadPkcs12(tls_certificate.pkcs12(), tls_certificate.pkcs12Path(),
   202→                                         tls_certificate.password());
   203→      } else {
   204→        creation_status = ctx.loadCertificateChain(tls_certificate.certificateChain(),
   205→                                                   tls_certificate.certificateChainPath());
   206→      }
   207→      if (!creation_status.ok()) {
   208→        return;
   209→      }
   210→      // The must staple extension means the certificate promises to carry
   211→      // with it an OCSP staple. https://tools.ietf.org/html/rfc7633#section-6
   212→      constexpr absl::string_view tls_feature_ext = "1.3.6.1.5.5.7.1.24";
   213→      constexpr absl::string_view must_staple_ext_value = "\x30\x3\x02\x01\x05";
   214→      auto must_staple = Utility::getCertificateExtensionValue(*ctx.cert_chain_, tls_feature_ext);
   215→      if (must_staple == must_staple_ext_value) {
   216→        ctx.is_must_staple_ = true;
   217→      }
   218→
   219→      bssl::UniquePtr<EVP_PKEY> public_key(X509_get_pubkey(ctx.cert_chain_.get()));
   220→      const int pkey_id = EVP_PKEY_id(public_key.get());
   221→      ctx.is_ecdsa_ = pkey_id == EVP_PKEY_EC;
   222→      switch (pkey_id) {
   223→      case EVP_PKEY_EC: {
   224→        // We only support P-256 ECDSA today.
   225→        const EC_KEY* ecdsa_public_key = EVP_PKEY_get0_EC_KEY(public_key.get());
   226→        // Since we checked the key type above, this should be valid.
   227→        ASSERT(ecdsa_public_key != nullptr);
   228→        const EC_GROUP* ecdsa_group = EC_KEY_get0_group(ecdsa_public_key);
   229→        if (ecdsa_group == nullptr ||
   230→            EC_GROUP_get_curve_name(ecdsa_group) != NID_X9_62_prime256v1) {
   231→          creation_status = absl::InvalidArgumentError(
   232→              fmt::format("Failed to load certificate chain from {}, only P-256 "
   233→                          "ECDSA certificates are supported",
   234→                          ctx.cert_chain_file_path_));
   235→          return;
   236→        }
   237→        ctx.is_ecdsa_ = true;
   238→      } break;
   239→      case EVP_PKEY_RSA: {
   240→        // We require RSA certificates with 2048-bit or larger keys.
   241→        const RSA* rsa_public_key = EVP_PKEY_get0_RSA(public_key.get());
   242→        // Since we checked the key type above, this should be valid.
   243→        ASSERT(rsa_public_key != nullptr);
   244→        const unsigned rsa_key_length = RSA_bits(rsa_public_key);
   245→#ifdef BORINGSSL_FIPS
   246→        if (rsa_key_length != 2048 && rsa_key_length != 3072 && rsa_key_length != 4096) {
   247→          creation_status = absl::InvalidArgumentError(
   248→              fmt::format("Failed to load certificate chain from {}, only RSA certificates with "
   249→                          "2048-bit, 3072-bit or 4096-bit keys are supported in FIPS mode",
   250→                          ctx.cert_chain_file_path_));
   251→          return;
   252→        }
   253→#else
   254→        if (rsa_key_length < 2048) {
   255→          creation_status = absl::InvalidArgumentError(
   256→              fmt::format("Failed to load certificate chain from {}, only RSA "
   257→                          "certificates with 2048-bit or larger keys are supported",
   258→                          ctx.cert_chain_file_path_));
   259→          return;
   260→        }
   261→#endif
   262→      } break;
   263→#ifdef BORINGSSL_FIPS
   264→      default:
   265→        creation_status = absl::InvalidArgumentError(
   266→            fmt::format("Failed to load certificate chain from {}, only RSA and "
   267→                        "ECDSA certificates are supported in FIPS mode",
   268→                        ctx.cert_chain_file_path_));
   269→        return;
   270→#endif
   271→      }
   272→
   273→      Envoy::Ssl::PrivateKeyMethodProviderSharedPtr private_key_method_provider =
   274→          tls_certificate.privateKeyMethod();
   275→      // We either have a private key or a BoringSSL private key method provider.
   276→      if (private_key_method_provider) {
   277→        ctx.private_key_method_provider_ = private_key_method_provider;
   278→        // The provider has a reference to the private key method for the context lifetime.
   279→        Ssl::BoringSslPrivateKeyMethodSharedPtr private_key_method =
   280→            private_key_method_provider->getBoringSslPrivateKeyMethod();
   281→        if (private_key_method == nullptr) {
   282→          creation_status = absl::InvalidArgumentError(
   283→              fmt::format("Failed to get BoringSSL private key method from provider"));
   284→          return;
   285→        }
   286→#ifdef BORINGSSL_FIPS
   287→        if (!ctx.private_key_method_provider_->checkFips()) {
   288→          creation_status = absl::InvalidArgumentError(
   289→              fmt::format("Private key method doesn't support FIPS mode with current parameters"));
   290→          return;
   291→        }
   292→#endif
   293→        SSL_CTX_set_private_key_method(ctx.ssl_ctx_.get(), private_key_method.get());
   294→      } else if (!tls_certificate.privateKey().empty()) {
   295→        // Load private key.
   296→        creation_status =
   297→            ctx.loadPrivateKey(tls_certificate.privateKey(), tls_certificate.privateKeyPath(),
   298→                               tls_certificate.password());
   299→        if (!creation_status.ok()) {
   300→          return;
   301→        }
   302→      }
   303→
   304→      if (additional_init != nullptr) {
   305→        absl::Status init_status = additional_init(ctx, tls_certificate);
   306→        SET_AND_RETURN_IF_NOT_OK(creation_status, init_status);
   307→      }
   308→    }
   309→  }
   310→
   311→  // use the server's cipher list preferences
   312→  for (auto& ctx : tls_contexts_) {
   313→    SSL_CTX_set_options(ctx.ssl_ctx_.get(), SSL_OP_CIPHER_SERVER_PREFERENCE);
   314→  }
   315→
   316→  parsed_alpn_protocols_ = parseAlpnProtocols(config.alpnProtocols(), creation_status);
   317→  SET_AND_RETURN_IF_NOT_OK(creation_status, creation_status);
   318→
   319→#if BORINGSSL_API_VERSION >= 21
   320→  // Register stat names based on lists reported by BoringSSL.
   321→  std::vector<const char*> list(SSL_get_all_cipher_names(nullptr, 0));
   322→  SSL_get_all_cipher_names(list.data(), list.size());
   323→  stat_name_set_->rememberBuiltins(list);
   324→
   325→  list.resize(SSL_get_all_curve_names(nullptr, 0));
   326→  SSL_get_all_curve_names(list.data(), list.size());
   327→  stat_name_set_->rememberBuiltins(list);
   328→
   329→  list.resize(SSL_get_all_signature_algorithm_names(nullptr, 0));
   330→  SSL_get_all_signature_algorithm_names(list.data(), list.size());
   331→  stat_name_set_->rememberBuiltins(list);
   332→
   333→  list.resize(SSL_get_all_version_names(nullptr, 0));
   334→  SSL_get_all_version_names(list.data(), list.size());
   335→  stat_name_set_->rememberBuiltins(list);
   336→#else
   337→  // Use the SSL library to iterate over the configured ciphers.
   338→  //
   339→  // Note that if a negotiated cipher suite is outside of this set, we'll issue an ENVOY_BUG.
   340→  for (Ssl::TlsContext& tls_context : tls_contexts_) {
   341→    for (const SSL_CIPHER* cipher : SSL_CTX_get_ciphers(tls_context.ssl_ctx_.get())) {
   342→      stat_name_set_->rememberBuiltin(SSL_CIPHER_get_name(cipher));
   343→    }
   344→  }
   345→
   346→  // Add supported cipher suites from the TLS 1.3 spec:
   347→  // https://tools.ietf.org/html/rfc8446#appendix-B.4
   348→  // AES-CCM cipher suites are removed (no BoringSSL support).
   349→  //
   350→  // Note that if a negotiated cipher suite is outside of this set, we'll issue an ENVOY_BUG.
   351→  stat_name_set_->rememberBuiltins(
   352→      {"TLS_AES_128_GCM_SHA256", "TLS_AES_256_GCM_SHA384", "TLS_CHACHA20_POLY1305_SHA256"});
   353→
   354→  // All supported curves. Source:
   355→  // https://github.com/google/boringssl/blob/3743aafdacff2f7b083615a043a37101f740fa53/ssl/ssl_key_share.cc#L302-L309
   356→  //
   357→  // Note that if a negotiated curve is outside of this set, we'll issue an ENVOY_BUG.
   358→  stat_name_set_->rememberBuiltins({"P-224", "P-256", "P-384", "P-521", "X25519", "CECPQ2"});
   359→
   360→  // All supported signature algorithms. Source:
   361→  // https://github.com/google/boringssl/blob/3743aafdacff2f7b083615a043a37101f740fa53/ssl/ssl_privkey.cc#L436-L453
   362→  //
   363→  // Note that if a negotiated algorithm is outside of this set, we'll issue an ENVOY_BUG.
   364→  stat_name_set_->rememberBuiltins({
   365→      "rsa_pkcs1_md5_sha1",
   366→      "rsa_pkcs1_sha1",
   367→      "rsa_pkcs1_sha256",
   368→      "rsa_pkcs1_sha384",
   369→      "rsa_pkcs1_sha512",
   370→      "ecdsa_sha1",
   371→      "ecdsa_secp256r1_sha256",
   372→      "ecdsa_secp384r1_sha384",
   373→      "ecdsa_secp521r1_sha512",
   374→      "rsa_pss_rsae_sha256",
   375→      "rsa_pss_rsae_sha384",
   376→      "rsa_pss_rsae_sha512",
   377→      "ed25519",
   378→  });
   379→
   380→  // All supported protocol versions.
   381→  //
   382→  // Note that if a negotiated version is outside of this set, we'll issue an ENVOY_BUG.
   383→  stat_name_set_->rememberBuiltins({"TLSv1", "TLSv1.1", "TLSv1.2", "TLSv1.3"});
   384→#endif
   385→
   386→  // As late as possible, run the custom SSL_CTX configuration callback on each
   387→  // SSL_CTX, if set.
   388→  if (auto sslctx_cb = config.sslctxCb(); sslctx_cb) {
   389→    for (Ssl::TlsContext& ctx : tls_contexts_) {
   390→      sslctx_cb(ctx.ssl_ctx_.get());
   391→    }
   392→  }
   393→
   394→  if (!config.tlsKeyLogPath().empty()) {
   395→    ENVOY_LOG(debug, "Enable tls key log");
   396→    auto file_or_error = config.accessLogManager().createAccessLog(
   397→        Filesystem::FilePathAndType{Filesystem::DestinationType::File, config.tlsKeyLogPath()});
   398→    SET_AND_RETURN_IF_NOT_OK(file_or_error.status(), creation_status);
   399→    tls_keylog_file_ = file_or_error.value();
   400→    for (auto& context : tls_contexts_) {
   401→      SSL_CTX* ctx = context.ssl_ctx_.get();
   402→      ASSERT(ctx != nullptr);
   403→      SSL_CTX_set_keylog_callback(ctx, keylogCallback);
   404→    }
   405→  }
   406→}
