   543→void ContextImpl::incCounter(const Stats::StatName name, absl::string_view value,
   544→                             const Stats::StatName fallback) const {
   545→  const Stats::StatName value_stat_name = stat_name_set_->getBuiltin(value, fallback);
   546→  ENVOY_BUG(value_stat_name != fallback,
   547→            absl::StrCat("Unexpected ", scope_.symbolTable().toString(name), " value: ", value));
   548→  Stats::Utility::counterFromElements(scope_, {name, value_stat_name}).inc();
