   550→
   551→void ContextImpl::logHandshake(SSL* ssl) const {
   552→  stats_.handshake_.inc();
   553→
   554→  if (SSL_session_reused(ssl)) {
   555→    stats_.session_reused_.inc();
   556→  }
   557→
   558→  incCounter(ssl_ciphers_, SSL_get_cipher_name(ssl), unknown_ssl_cipher_);
   559→  incCounter(ssl_versions_, SSL_get_version(ssl), unknown_ssl_version_);
   560→
   561→  const uint16_t curve_id = SSL_get_curve_id(ssl);
   562→  if (curve_id) {
   563→    incCounter(ssl_curves_, SSL_get_curve_name(curve_id), unknown_ssl_curve_);
   564→  }
   565→
   566→  const uint16_t sigalg_id = SSL_get_peer_signature_algorithm(ssl);
   567→  if (sigalg_id) {
   568→    const char* sigalg = SSL_get_signature_algorithm_name(sigalg_id, 1 /* include curve */);
   569→    incCounter(ssl_sigalgs_, sigalg, unknown_ssl_algorithm_);
   570→  }
   571→
   572→  bssl::UniquePtr<X509> cert(SSL_get_peer_certificate(ssl));
   573→  if (!cert.get()) {
   574→    stats_.no_certificate_.inc();
   575→  }
   576→
   577→#if defined(BORINGSSL_FIPS) && BORINGSSL_API_VERSION >= 18
   578→#error "Delete preprocessor check below; no longer needed"
   579→#endif
   580→
   581→#if BORINGSSL_API_VERSION >= 18
   582→  // Increment the `was_key_usage_invalid_` stats to indicate the given cert would have triggered an
   583→  // error but is allowed because the enforcement that rsa key usage and tls usage need to be
   584→  // matched has been disabled.
   585→  if (SSL_was_key_usage_invalid(ssl)) {
   586→    stats_.was_key_usage_invalid_.inc();
   587→  }
   588→#endif // BORINGSSL_API_VERSION
   589→}
