   811→absl::Status TlsContext::checkPrivateKey(const bssl::UniquePtr<EVP_PKEY>& pkey,
   812→                                         const std::string& key_path) {
   813→#ifdef BORINGSSL_FIPS
   814→  // Verify that private keys are passing FIPS pairwise consistency tests.
   815→  switch (EVP_PKEY_id(pkey.get())) {
   816→  case EVP_PKEY_EC: {
   817→    const EC_KEY* ecdsa_private_key = EVP_PKEY_get0_EC_KEY(pkey.get());
   818→    if (!EC_KEY_check_fips(ecdsa_private_key)) {
   819→      return absl::InvalidArgumentError(
   820→          fmt::format("Failed to load private key from {}, ECDSA key failed "
   821→                      "pairwise consistency test required in FIPS mode",
   822→                      key_path));
   823→    }
   824→  } break;
   825→  case EVP_PKEY_RSA: {
   826→    RSA* rsa_private_key = EVP_PKEY_get0_RSA(pkey.get());
   827→    if (!RSA_check_fips(rsa_private_key)) {
   828→      return absl::InvalidArgumentError(
   829→          fmt::format("Failed to load private key from {}, RSA key failed "
   830→                      "pairwise consistency test required in FIPS mode",
   831→                      key_path));
   832→    }
   833→  } break;
   834→  }
   835→#else
   836→  UNREFERENCED_PARAMETER(pkey);
   837→  UNREFERENCED_PARAMETER(key_path);
   838→#endif
   839→  return absl::OkStatus();
   840→}
