   117→      }
   118→    }
   119→  }
   120→
   121→  if (config_ != nullptr && !config_->certificateRevocationList().empty()) {
   122→    bssl::UniquePtr<BIO> bio(
   123→        BIO_new_mem_buf(const_cast<char*>(config_->certificateRevocationList().data()),
   124→                        config_->certificateRevocationList().size()));
   125→    RELEASE_ASSERT(bio != nullptr, "");
   126→
   127→    // Based on BoringSSL's X509_load_cert_crl_file().
   128→    bssl::UniquePtr<STACK_OF(X509_INFO)> list(
   129→        PEM_X509_INFO_read_bio(bio.get(), nullptr, nullptr, nullptr));
   130→    if (list == nullptr) {
   131→      return absl::InvalidArgumentError(
   132→          absl::StrCat("Failed to load CRL from ", config_->certificateRevocationListPath()));
   133→    }
   134→
