   481→absl::Status DefaultCertValidator::addClientValidationContext(SSL_CTX* ctx,
   482→                                                              bool require_client_cert) {
   483→  if (config_ == nullptr || config_->caCert().empty()) {
   484→    return absl::OkStatus();
   485→  }
   486→
   487→  bssl::UniquePtr<BIO> bio(
   488→      BIO_new_mem_buf(const_cast<char*>(config_->caCert().data()), config_->caCert().size()));
   489→  RELEASE_ASSERT(bio != nullptr, "");
   490→  // Based on BoringSSL's SSL_add_file_cert_subjects_to_stack().
   491→  // Use a generic lambda to be compatible with BoringSSL before and after
   492→  // https://boringssl-review.googlesource.com/c/boringssl/+/56190
   493→  bssl::UniquePtr<STACK_OF(X509_NAME)> list(
   494→      sk_X509_NAME_new([](auto* a, auto* b) -> int { return X509_NAME_cmp(*a, *b); }));
   495→  RELEASE_ASSERT(list != nullptr, "");
   496→  for (;;) {
   497→    bssl::UniquePtr<X509> cert(PEM_read_bio_X509(bio.get(), nullptr, nullptr, nullptr));
   498→    if (cert == nullptr) {
   499→      break;
   500→    }
   501→    X509_NAME* name = X509_get_subject_name(cert.get());
   502→    if (name == nullptr) {
   503→      return absl::InvalidArgumentError(absl::StrCat(
   504→          "Failed to load trusted client CA certificates from ", config_->caCertPath()));
   505→    }
   506→    // Check for duplicates.
   507→    if (sk_X509_NAME_find(list.get(), nullptr, name)) {
   508→      continue;
   509→    }
   510→    bssl::UniquePtr<X509_NAME> name_dup(X509_NAME_dup(name));
   511→    if (name_dup == nullptr || !sk_X509_NAME_push(list.get(), name_dup.release())) {
   512→      return absl::InvalidArgumentError(absl::StrCat(
   513→          "Failed to load trusted client CA certificates from ", config_->caCertPath()));
   514→    }
   515→  }
   516→
   517→  // Check for EOF.
   518→  const uint32_t err = ERR_peek_last_error();
   519→  if (ERR_GET_LIB(err) == ERR_LIB_PEM && ERR_GET_REASON(err) == PEM_R_NO_START_LINE) {
   520→    ERR_clear_error();
   521→  } else {
   522→    return absl::InvalidArgumentError(
   523→        absl::StrCat("Failed to load trusted client CA certificates from ", config_->caCertPath()));
   524→  }
   525→  SSL_CTX_set_client_CA_list(ctx, list.release());
   526→
   527→  if (require_client_cert) {
   528→    SSL_CTX_set_verify(ctx, SSL_VERIFY_PEER | SSL_VERIFY_FAIL_IF_NO_PEER_CERT, nullptr);
   529→  }
   530→  // Set the verify_depth
   531→  if (config_->maxVerifyDepth().has_value()) {
   532→    uint32_t max_verify_depth = std::min(config_->maxVerifyDepth().value(), uint32_t{INT_MAX});
   533→#if BORINGSSL_API_VERSION >= 29
   534→    // Older BoringSSLs behave like OpenSSL 1.0.x and exclude the leaf from the
   535→    // depth but include the trust anchor. Newer BoringSSLs match OpenSSL 1.1.x
   536→    // and later in excluding both the leaf and trust anchor. `maxVerifyDepth`
   537→    // documents the older behavior, so adjust the value to match.
   538→    max_verify_depth = max_verify_depth > 0 ? max_verify_depth - 1 : 0;
   539→#endif
   540→    SSL_CTX_set_verify_depth(ctx, static_cast<int>(max_verify_depth));
   541→  }
   542→  return absl::OkStatus();
   543→}
