   222→Envoy::Ssl::ClientValidationStatus
   223→DefaultCertValidator::verifyCertificate(X509* cert, const std::vector<std::string>& verify_san_list,
   224→                                        const std::vector<SanMatcherPtr>& subject_alt_name_matchers,
   225→                                        std::string* error_details, uint8_t* out_alert) {
   226→  Envoy::Ssl::ClientValidationStatus validated = Envoy::Ssl::ClientValidationStatus::NotValidated;
   227→  if (!verify_san_list.empty()) {
   228→    if (!verifySubjectAltName(cert, verify_san_list)) {
   229→      const char* error = "verify cert failed: verify SAN list";
   230→      if (error_details != nullptr) {
   231→        *error_details = error;
   232→      }
   233→      ENVOY_LOG(debug, error);
   234→      stats_.fail_verify_san_.inc();
   235→      return Envoy::Ssl::ClientValidationStatus::Failed;
   236→    }
   237→    validated = Envoy::Ssl::ClientValidationStatus::Validated;
   238→  }
   239→
   240→  if (!subject_alt_name_matchers.empty()) {
   241→    if (!matchSubjectAltName(cert, subject_alt_name_matchers)) {
   242→      const char* error = "verify cert failed: SAN matcher";
   243→      if (error_details != nullptr) {
   244→        *error_details = error;
   245→      }
   246→      ENVOY_LOG(debug, error);
   247→      stats_.fail_verify_san_.inc();
   248→      return Envoy::Ssl::ClientValidationStatus::Failed;
   249→    }
   250→    validated = Envoy::Ssl::ClientValidationStatus::Validated;
   251→  }
   252→
   253→  if (!verify_certificate_hash_list_.empty() || !verify_certificate_spki_list_.empty()) {
   254→    const bool valid_certificate_hash =
   255→        !verify_certificate_hash_list_.empty() &&
   256→        verifyCertificateHashList(cert, verify_certificate_hash_list_);
   257→    const bool valid_certificate_spki =
   258→        !verify_certificate_spki_list_.empty() &&
   259→        verifyCertificateSpkiList(cert, verify_certificate_spki_list_);
   260→
   261→    if (!valid_certificate_hash && !valid_certificate_spki) {
   262→      if (out_alert != nullptr) {
   263→        *out_alert = SSL_AD_BAD_CERTIFICATE_HASH_VALUE;
   264→      }
   265→      const char* error = "verify cert failed: cert hash and spki";
   266→      if (error_details != nullptr) {
   267→        *error_details = error;
   268→      }
   269→      ENVOY_LOG(debug, error);
   270→      stats_.fail_verify_cert_hash_.inc();
   271→      return Envoy::Ssl::ClientValidationStatus::Failed;
   272→    }
   273→
   274→    validated = Envoy::Ssl::ClientValidationStatus::Validated;
   275→  }
   276→
   277→  return validated;
   278→}
   279→
   280→ValidationResults DefaultCertValidator::doVerifyCertChain(
   281→    STACK_OF(X509)& cert_chain, Ssl::ValidateResultCallbackPtr /*callback*/,
   282→    const Network::TransportSocketOptionsConstSharedPtr& transport_socket_options, SSL_CTX& ssl_ctx,
   283→    const CertValidator::ExtraValidationContext& /*validation_context*/, bool is_server,
   284→    absl::string_view /*host_name*/) {
   285→  if (sk_X509_num(&cert_chain) == 0) {
   286→    stats_.fail_verify_error_.inc();
   287→    const char* error = "verify cert failed: empty cert chain";
   288→    ENVOY_LOG(debug, error);
   289→    return {ValidationResults::ValidationStatus::Failed,
   290→            Envoy::Ssl::ClientValidationStatus::NoClientCertificate, absl::nullopt, error};
   291→  }
   292→  Envoy::Ssl::ClientValidationStatus detailed_status =
   293→      Envoy::Ssl::ClientValidationStatus::NotValidated;
   294→  X509* leaf_cert = sk_X509_value(&cert_chain, 0);
   295→  ASSERT(leaf_cert);
   296→  if (verify_trusted_ca_) {
   297→    X509_STORE* verify_store = SSL_CTX_get_cert_store(&ssl_ctx);
   298→    ASSERT(verify_store);
   299→    bssl::UniquePtr<X509_STORE_CTX> ctx(X509_STORE_CTX_new());
   300→    if (!ctx || !X509_STORE_CTX_init(ctx.get(), verify_store, leaf_cert, &cert_chain) ||
   301→        // We need to inherit the verify parameters. These can be determined by
   302→        // the context: if it's a server it will verify SSL client certificates or
   303→        // vice versa.
   304→        !X509_STORE_CTX_set_default(ctx.get(), is_server ? "ssl_client" : "ssl_server") ||
   305→        // Anything non-default in "param" should overwrite anything in the ctx.
   306→        !X509_VERIFY_PARAM_set1(X509_STORE_CTX_get0_param(ctx.get()),
   307→                                SSL_CTX_get0_param(&ssl_ctx))) {
   308→      OPENSSL_PUT_ERROR(SSL, ERR_R_X509_LIB);
   309→      const char* error = "verify cert failed: init and setup X509_STORE_CTX";
   310→      stats_.fail_verify_error_.inc();
   311→      ENVOY_LOG(debug, error);
   312→      return {ValidationResults::ValidationStatus::Failed,
   313→              Envoy::Ssl::ClientValidationStatus::Failed, absl::nullopt, error};
   314→    }
   315→    const bool verify_succeeded = (X509_verify_cert(ctx.get()) == 1);
   316→
   317→    if (!verify_succeeded) {
   318→      const std::string error =
   319→          absl::StrCat("verify cert failed: ", Utility::getX509VerificationErrorInfo(ctx.get()));
   320→      stats_.fail_verify_error_.inc();
   321→      ENVOY_LOG(debug, error);
   322→      if (allow_untrusted_certificate_) {
   323→        return ValidationResults{ValidationResults::ValidationStatus::Successful,
   324→                                 Envoy::Ssl::ClientValidationStatus::Failed, absl::nullopt,
   325→                                 absl::nullopt};
   326→      }
   327→      return {ValidationResults::ValidationStatus::Failed,
   328→              Envoy::Ssl::ClientValidationStatus::Failed,
   329→              SSL_alert_from_verify_result(X509_STORE_CTX_get_error(ctx.get())), error};
   330→    }
   331→    detailed_status = Envoy::Ssl::ClientValidationStatus::Validated;
   332→  }
   333→  std::string error_details;
   334→  uint8_t tls_alert = SSL_AD_CERTIFICATE_UNKNOWN;
   335→  const bool succeeded = verifyCertAndUpdateStatus(leaf_cert, transport_socket_options.get(),
   336→                                                   detailed_status, &error_details, &tls_alert);
   337→  return succeeded ? ValidationResults{ValidationResults::ValidationStatus::Successful,
   338→                                       detailed_status, absl::nullopt, absl::nullopt}
   339→                   : ValidationResults{ValidationResults::ValidationStatus::Failed, detailed_status,
   340→                                       tls_alert, error_details};
   341→}
   342→
   343→bool DefaultCertValidator::verifySubjectAltName(X509* cert,
   344→                                                const std::vector<std::string>& subject_alt_names) {
   345→  bssl::UniquePtr<GENERAL_NAMES> san_names(
   346→      static_cast<GENERAL_NAMES*>(X509_get_ext_d2i(cert, NID_subject_alt_name, nullptr, nullptr)));
   347→  if (san_names == nullptr) {
   348→    return false;
   349→  }
   350→  for (const GENERAL_NAME* general_name : san_names.get()) {
   351→    const std::string san = Utility::generalNameAsString(general_name);
   352→    for (auto& config_san : subject_alt_names) {
   353→      if (general_name->type == GEN_DNS ? Utility::dnsNameMatch(config_san, san.c_str())
   354→                                        : config_san == san) {
   355→        return true;
   356→      }
   357→    }
   358→  }
   359→  return false;
   360→}
   361→
   362→bool DefaultCertValidator::matchSubjectAltName(
   363→    X509* cert, const std::vector<SanMatcherPtr>& subject_alt_name_matchers) {
   364→  bssl::UniquePtr<GENERAL_NAMES> san_names(
   365→      static_cast<GENERAL_NAMES*>(X509_get_ext_d2i(cert, NID_subject_alt_name, nullptr, nullptr)));
   366→  if (san_names == nullptr) {
   367→    return false;
   368→  }
   369→  for (const auto& config_san_matcher : subject_alt_name_matchers) {
   370→    for (const GENERAL_NAME* general_name : san_names.get()) {
   371→      if (config_san_matcher->match(general_name)) {
   372→        return true;
   373→      }
   374→    }
   375→  }
   376→  return false;
   377→}
   378→
   379→bool DefaultCertValidator::verifyCertificateSpkiList(
   380→    X509* cert, const std::vector<std::vector<uint8_t>>& expected_hashes) {
   381→  X509_PUBKEY* pubkey = X509_get_X509_PUBKEY(cert);
   382→  if (pubkey == nullptr) {
   383→    return false;
   384→  }
   385→  uint8_t* spki = nullptr;
   386→  const int len = i2d_X509_PUBKEY(pubkey, &spki);
   387→  if (len < 0) {
   388→    return false;
   389→  }
   390→  bssl::UniquePtr<uint8_t> free_spki(spki);
   391→
   392→  std::vector<uint8_t> computed_hash(SHA256_DIGEST_LENGTH);
   393→  SHA256(spki, len, computed_hash.data());
   394→
   395→  for (const auto& expected_hash : expected_hashes) {
   396→    if (computed_hash == expected_hash) {
   397→      return true;
   398→    }
   399→  }
   400→  return false;
   401→}
   402→
   403→bool DefaultCertValidator::verifyCertificateHashList(
   404→    X509* cert, const std::vector<std::vector<uint8_t>>& expected_hashes) {
   405→  std::vector<uint8_t> computed_hash(SHA256_DIGEST_LENGTH);
   406→  unsigned int n;
   407→  X509_digest(cert, EVP_sha256(), computed_hash.data(), &n);
   408→  RELEASE_ASSERT(n == computed_hash.size(), "");
   409→
   410→  for (const auto& expected_hash : expected_hashes) {
   411→    if (computed_hash == expected_hash) {
   412→      return true;
   413→    }
   414→  }
   415→  return false;
   416→}
