   556→class DefaultCertValidatorFactory : public CertValidatorFactory {
   557→public:
   558→  CertValidatorPtr
   559→  createCertValidator(const Envoy::Ssl::CertificateValidationContextConfig* config, SslStats& stats,
   560→                      Server::Configuration::CommonFactoryContext& context) override {
   561→    return std::make_unique<DefaultCertValidator>(config, stats, context);
   562→  }
