    77→    RELEASE_ASSERT(bio != nullptr, "");
    78→    // Based on BoringSSL's X509_load_cert_crl_file().
    79→    bssl::UniquePtr<STACK_OF(X509_INFO)> list(
    80→        PEM_X509_INFO_read_bio(bio.get(), nullptr, nullptr, nullptr));
    81→    if (list == nullptr) {
    82→      return absl::InvalidArgumentError(
    83→          absl::StrCat("Failed to load trusted CA certificates from ", config_->caCertPath()));
    84→    }
    85→
    86→    for (auto& ctx : contexts) {
    87→      X509_STORE* store = SSL_CTX_get_cert_store(ctx);
    88→      X509_STORE_set_flags(store, X509_V_FLAG_PARTIAL_CHAIN);
    89→      bool has_crl = false;
    90→      for (const X509_INFO* item : list.get()) {
    91→        if (item->x509) {
    92→          X509_STORE_add_cert(store, item->x509);
    93→          if (ca_cert_ == nullptr) {
    94→            X509_up_ref(item->x509);
    95→            ca_cert_.reset(item->x509);
    96→          }
    97→        }
    98→        if (item->crl) {
    99→          X509_STORE_add_crl(store, item->crl);
   100→          has_crl = true;
   101→        }
   102→      }
   103→      if (ca_cert_ == nullptr) {
   104→        return absl::InvalidArgumentError(
   105→            absl::StrCat("Failed to load trusted CA certificates from ", config_->caCertPath()));
   106→      }
   107→      if (has_crl) {
   108→        X509_STORE_set_flags(store, config_->onlyVerifyLeafCertificateCrl()
   109→                                        ? X509_V_FLAG_CRL_CHECK
   110→                                        : X509_V_FLAG_CRL_CHECK | X509_V_FLAG_CRL_CHECK_ALL);
   111→      }
   112→      verify_mode = SSL_VERIFY_PEER;
   113→      verify_trusted_ca_ = true;
   114→
   115→      if (config_->allowExpiredCertificate()) {
   116→        CertValidatorUtil::setIgnoreCertificateExpiration(store);
   117→      }
   118→    }
   119→  }
   120→
   121→  if (config_ != nullptr && !config_->certificateRevocationList().empty()) {
   122→    bssl::UniquePtr<BIO> bio(
   123→        BIO_new_mem_buf(const_cast<char*>(config_->certificateRevocationList().data()),
   124→                        config_->certificateRevocationList().size()));
   125→    RELEASE_ASSERT(bio != nullptr, "");
   126→
   127→    // Based on BoringSSL's X509_load_cert_crl_file().
   128→    bssl::UniquePtr<STACK_OF(X509_INFO)> list(
   129→        PEM_X509_INFO_read_bio(bio.get(), nullptr, nullptr, nullptr));
   130→    if (list == nullptr) {
   131→      return absl::InvalidArgumentError(
   132→          absl::StrCat("Failed to load CRL from ", config_->certificateRevocationListPath()));
   133→    }
   134→
   135→    for (auto& ctx : contexts) {
   136→      X509_STORE* store = SSL_CTX_get_cert_store(ctx);
   137→      X509_STORE_set_flags(store, X509_V_FLAG_PARTIAL_CHAIN);
   138→      for (const X509_INFO* item : list.get()) {
   139→        if (item->crl) {
   140→          X509_STORE_add_crl(store, item->crl);
   141→        }
   142→      }
   143→      X509_STORE_set_flags(store, config_->onlyVerifyLeafCertificateCrl()
   144→                                      ? X509_V_FLAG_CRL_CHECK
   145→                                      : X509_V_FLAG_CRL_CHECK | X509_V_FLAG_CRL_CHECK_ALL);
   146→    }
   147→  }
   148→
   149→  const Envoy::Ssl::CertificateValidationContextConfig* cert_validation_config = config_;
   150→  if (cert_validation_config != nullptr) {
   151→    if (!cert_validation_config->subjectAltNameMatchers().empty()) {
   152→      for (const envoy::extensions::transport_sockets::tls::v3::SubjectAltNameMatcher& matcher :
   153→           cert_validation_config->subjectAltNameMatchers()) {
   154→        auto san_matcher = createStringSanMatcher(matcher, context_);
   155→        if (san_matcher == nullptr) {
   156→          return absl::InvalidArgumentError(
   157→              absl::StrCat("Failed to create string SAN matcher of type ", matcher.san_type()));
   158→        }
   159→        subject_alt_name_matchers_.push_back(std::move(san_matcher));
   160→      }
   161→      verify_mode = verify_mode_validation_context;
   162→    }
   163→
   164→    if (!cert_validation_config->verifyCertificateHashList().empty()) {
   165→      for (auto hash : cert_validation_config->verifyCertificateHashList()) {
   166→        // Remove colons from the 95 chars long colon-separated "fingerprint"
   167→        // in order to get the hex-encoded string.
   168→        if (hash.size() == 95) {
   169→          hash.erase(std::remove(hash.begin(), hash.end(), ':'), hash.end());
   170→        }
   171→        const auto& decoded = Hex::decode(hash);
   172→        if (decoded.size() != SHA256_DIGEST_LENGTH) {
   173→          return absl::InvalidArgumentError(absl::StrCat("Invalid hex-encoded SHA-256 ", hash));
   174→        }
   175→        verify_certificate_hash_list_.push_back(decoded);
   176→      }
   177→      verify_mode = verify_mode_validation_context;
   178→    }
   179→
   180→    if (!cert_validation_config->verifyCertificateSpkiList().empty()) {
   181→      for (const auto& hash : cert_validation_config->verifyCertificateSpkiList()) {
   182→        const auto decoded = Base64::decode(hash);
   183→        if (decoded.size() != SHA256_DIGEST_LENGTH) {
   184→          return absl::InvalidArgumentError(absl::StrCat("Invalid base64-encoded SHA-256 ", hash));
   185→        }
   186→        verify_certificate_spki_list_.emplace_back(decoded.begin(), decoded.end());
   187→      }
   188→      verify_mode = verify_mode_validation_context;
   189→    }
   190→  }
   191→
   192→  return verify_mode;
   193→}
   194→
   195→bool DefaultCertValidator::verifyCertAndUpdateStatus(
   196→    X509* leaf_cert, const Network::TransportSocketOptions* transport_socket_options,
   197→    Envoy::Ssl::ClientValidationStatus& detailed_status, std::string* error_details,
   198→    uint8_t* out_alert) {
   199→  Envoy::Ssl::ClientValidationStatus validated =
   200→      verifyCertificate(leaf_cert,
   201→                        transport_socket_options != nullptr
   202→                            ? transport_socket_options->verifySubjectAltNameListOverride()
   203→                            : std::vector<std::string>{},
   204→                        subject_alt_name_matchers_, error_details, out_alert);
   205→
   206→  if (detailed_status == Envoy::Ssl::ClientValidationStatus::NotValidated ||
   207→      validated != Envoy::Ssl::ClientValidationStatus::NotValidated) {
   208→    detailed_status = validated;
   209→  }
   210→
   211→  // If `trusted_ca` exists, it is already verified in the code above. Thus, we just need to make
   212→  // sure the verification for other validation context configurations doesn't fail (i.e. either
   213→  // `NotValidated` or `Validated`). If `trusted_ca` doesn't exist, we will need to make sure
   214→  // other configurations are verified and the verification succeed.
   215→  const bool success = verify_trusted_ca_
   216→                           ? validated != Envoy::Ssl::ClientValidationStatus::Failed
   217→                           : validated == Envoy::Ssl::ClientValidationStatus::Validated;
   218→
   219→  return (allow_untrusted_certificate_ || success);
   220→}
   221→
   222→Envoy::Ssl::ClientValidationStatus
   223→DefaultCertValidator::verifyCertificate(X509* cert, const std::vector<std::string>& verify_san_list,
   224→                                        const std::vector<SanMatcherPtr>& subject_alt_name_matchers,
   225→                                        std::string* error_details, uint8_t* out_alert) {
   226→  Envoy::Ssl::ClientValidationStatus validated = Envoy::Ssl::ClientValidationStatus::NotValidated;
   227→  if (!verify_san_list.empty()) {
   228→    if (!verifySubjectAltName(cert, verify_san_list)) {
   229→      const char* error = "verify cert failed: verify SAN list";
   230→      if (error_details != nullptr) {
   231→        *error_details = error;
   232→      }
   233→      ENVOY_LOG(debug, error);
   234→      stats_.fail_verify_san_.inc();
   235→      return Envoy::Ssl::ClientValidationStatus::Failed;
   236→    }
   237→    validated = Envoy::Ssl::ClientValidationStatus::Validated;
   238→  }
   239→
   240→  if (!subject_alt_name_matchers.empty()) {
   241→    if (!matchSubjectAltName(cert, subject_alt_name_matchers)) {
   242→      const char* error = "verify cert failed: SAN matcher";
   243→      if (error_details != nullptr) {
   244→        *error_details = error;
   245→      }
   246→      ENVOY_LOG(debug, error);
   247→      stats_.fail_verify_san_.inc();
   248→      return Envoy::Ssl::ClientValidationStatus::Failed;
   249→    }
   250→    validated = Envoy::Ssl::ClientValidationStatus::Validated;
   251→  }
   252→
   253→  if (!verify_certificate_hash_list_.empty() || !verify_certificate_spki_list_.empty()) {
   254→    const bool valid_certificate_hash =
   255→        !verify_certificate_hash_list_.empty() &&
   256→        verifyCertificateHashList(cert, verify_certificate_hash_list_);
   257→    const bool valid_certificate_spki =
   258→        !verify_certificate_spki_list_.empty() &&
   259→        verifyCertificateSpkiList(cert, verify_certificate_spki_list_);
   260→
   261→    if (!valid_certificate_hash && !valid_certificate_spki) {
   262→      if (out_alert != nullptr) {
   263→        *out_alert = SSL_AD_BAD_CERTIFICATE_HASH_VALUE;
   264→      }
   265→      const char* error = "verify cert failed: cert hash and spki";
   266→      if (error_details != nullptr) {
   267→        *error_details = error;
   268→      }
   269→      ENVOY_LOG(debug, error);
   270→      stats_.fail_verify_cert_hash_.inc();
   271→      return Envoy::Ssl::ClientValidationStatus::Failed;
   272→    }
   273→
   274→    validated = Envoy::Ssl::ClientValidationStatus::Validated;
   275→  }
   276→
   277→  return validated;
   278→}
   279→
   280→ValidationResults DefaultCertValidator::doVerifyCertChain(
   281→    STACK_OF(X509)& cert_chain, Ssl::ValidateResultCallbackPtr /*callback*/,
   282→    const Network::TransportSocketOptionsConstSharedPtr& transport_socket_options, SSL_CTX& ssl_ctx,
   283→    const CertValidator::ExtraValidationContext& /*validation_context*/, bool is_server,
   284→    absl::string_view /*host_name*/) {
   285→  if (sk_X509_num(&cert_chain) == 0) {
   286→    stats_.fail_verify_error_.inc();
   287→    const char* error = "verify cert failed: empty cert chain";
   288→    ENVOY_LOG(debug, error);
   289→    return {ValidationResults::ValidationStatus::Failed,
   290→            Envoy::Ssl::ClientValidationStatus::NoClientCertificate, absl::nullopt, error};
   291→  }
   292→  Envoy::Ssl::ClientValidationStatus detailed_status =
   293→      Envoy::Ssl::ClientValidationStatus::NotValidated;
   294→  X509* leaf_cert = sk_X509_value(&cert_chain, 0);
   295→  ASSERT(leaf_cert);
   296→  if (verify_trusted_ca_) {
   297→    X509_STORE* verify_store = SSL_CTX_get_cert_store(&ssl_ctx);
   298→    ASSERT(verify_store);
   299→    bssl::UniquePtr<X509_STORE_CTX> ctx(X509_STORE_CTX_new());
   300→    if (!ctx || !X509_STORE_CTX_init(ctx.get(), verify_store, leaf_cert, &cert_chain) ||
   301→        // We need to inherit the verify parameters. These can be determined by
   302→        // the context: if it's a server it will verify SSL client certificates or
   303→        // vice versa.
   304→        !X509_STORE_CTX_set_default(ctx.get(), is_server ? "ssl_client" : "ssl_server") ||
   305→        // Anything non-default in "param" should overwrite anything in the ctx.
   306→        !X509_VERIFY_PARAM_set1(X509_STORE_CTX_get0_param(ctx.get()),
   307→                                SSL_CTX_get0_param(&ssl_ctx))) {
   308→      OPENSSL_PUT_ERROR(SSL, ERR_R_X509_LIB);
   309→      const char* error = "verify cert failed: init and setup X509_STORE_CTX";
   310→      stats_.fail_verify_error_.inc();
   311→      ENVOY_LOG(debug, error);
   312→      return {ValidationResults::ValidationStatus::Failed,
   313→              Envoy::Ssl::ClientValidationStatus::Failed, absl::nullopt, error};
   314→    }
   315→    const bool verify_succeeded = (X509_verify_cert(ctx.get()) == 1);
   316→
   317→    if (!verify_succeeded) {
   318→      const std::string error =
   319→          absl::StrCat("verify cert failed: ", Utility::getX509VerificationErrorInfo(ctx.get()));
   320→      stats_.fail_verify_error_.inc();
   321→      ENVOY_LOG(debug, error);
   322→      if (allow_untrusted_certificate_) {
   323→        return ValidationResults{ValidationResults::ValidationStatus::Successful,
   324→                                 Envoy::Ssl::ClientValidationStatus::Failed, absl::nullopt,
   325→                                 absl::nullopt};
   326→      }
   327→      return {ValidationResults::ValidationStatus::Failed,
   328→              Envoy::Ssl::ClientValidationStatus::Failed,
   329→              SSL_alert_from_verify_result(X509_STORE_CTX_get_error(ctx.get())), error};
   330→    }
   331→    detailed_status = Envoy::Ssl::ClientValidationStatus::Validated;
   332→  }
   333→  std::string error_details;
   334→  uint8_t tls_alert = SSL_AD_CERTIFICATE_UNKNOWN;
   335→  const bool succeeded = verifyCertAndUpdateStatus(leaf_cert, transport_socket_options.get(),
   336→                                                   detailed_status, &error_details, &tls_alert);
   337→  return succeeded ? ValidationResults{ValidationResults::ValidationStatus::Successful,
   338→                                       detailed_status, absl::nullopt, absl::nullopt}
   339→                   : ValidationResults{ValidationResults::ValidationStatus::Failed, detailed_status,
   340→                                       tls_alert, error_details};
   341→}
