   343→bool DefaultCertValidator::verifySubjectAltName(X509* cert,
   344→                                                const std::vector<std::string>& subject_alt_names) {
   345→  bssl::UniquePtr<GENERAL_NAMES> san_names(
   346→      static_cast<GENERAL_NAMES*>(X509_get_ext_d2i(cert, NID_subject_alt_name, nullptr, nullptr)));
   347→  if (san_names == nullptr) {
   348→    return false;
   349→  }
   350→  for (const GENERAL_NAME* general_name : san_names.get()) {
   351→    const std::string san = Utility::generalNameAsString(general_name);
   352→    for (auto& config_san : subject_alt_names) {
   353→      if (general_name->type == GEN_DNS ? Utility::dnsNameMatch(config_san, san.c_str())
   354→                                        : config_san == san) {
   355→        return true;
   356→      }
   357→    }
   358→  }
   359→  return false;
   360→}
   361→
   362→bool DefaultCertValidator::matchSubjectAltName(
   363→    X509* cert, const std::vector<SanMatcherPtr>& subject_alt_name_matchers) {
   364→  bssl::UniquePtr<GENERAL_NAMES> san_names(
   365→      static_cast<GENERAL_NAMES*>(X509_get_ext_d2i(cert, NID_subject_alt_name, nullptr, nullptr)));
   366→  if (san_names == nullptr) {
   367→    return false;
   368→  }
   369→  for (const auto& config_san_matcher : subject_alt_name_matchers) {
   370→    for (const GENERAL_NAME* general_name : san_names.get()) {
   371→      if (config_san_matcher->match(general_name)) {
   372→        return true;
   373→      }
   374→    }
   375→  }
   376→  return false;
   377→}
   378→
   379→bool DefaultCertValidator::verifyCertificateSpkiList(
   380→    X509* cert, const std::vector<std::vector<uint8_t>>& expected_hashes) {
   381→  X509_PUBKEY* pubkey = X509_get_X509_PUBKEY(cert);
   382→  if (pubkey == nullptr) {
   383→    return false;
   384→  }
   385→  uint8_t* spki = nullptr;
   386→  const int len = i2d_X509_PUBKEY(pubkey, &spki);
   387→  if (len < 0) {
   388→    return false;
   389→  }
   390→  bssl::UniquePtr<uint8_t> free_spki(spki);
   391→
   392→  std::vector<uint8_t> computed_hash(SHA256_DIGEST_LENGTH);
   393→  SHA256(spki, len, computed_hash.data());
   394→
   395→  for (const auto& expected_hash : expected_hashes) {
   396→    if (computed_hash == expected_hash) {
   397→      return true;
   398→    }
   399→  }
   400→  return false;
   401→}
   402→
   403→bool DefaultCertValidator::verifyCertificateHashList(
   404→    X509* cert, const std::vector<std::vector<uint8_t>>& expected_hashes) {
   405→  std::vector<uint8_t> computed_hash(SHA256_DIGEST_LENGTH);
   406→  unsigned int n;
   407→  X509_digest(cert, EVP_sha256(), computed_hash.data(), &n);
   408→  RELEASE_ASSERT(n == computed_hash.size(), "");
   409→
   410→  for (const auto& expected_hash : expected_hashes) {
   411→    if (computed_hash == expected_hash) {
   412→      return true;
   413→    }
   414→  }
   415→  return false;
   416→}
   417→
   418→void DefaultCertValidator::updateDigestForSessionId(bssl::ScopedEVP_MD_CTX& md,
   419→                                                    uint8_t hash_buffer[EVP_MAX_MD_SIZE],
   420→                                                    unsigned hash_length) {
   421→  int rc;
   422→
   423→  // Hash all the settings that affect whether the server will allow/accept
   424→  // the client connection. This ensures that the client is always validated against
   425→  // the correct settings, even if session resumption across different listeners
   426→  // is enabled.
   427→  if (ca_cert_ != nullptr) {
   428→    rc = X509_digest(ca_cert_.get(), EVP_sha256(), hash_buffer, &hash_length);
   429→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   430→    RELEASE_ASSERT(hash_length == SHA256_DIGEST_LENGTH,
   431→                   fmt::format("invalid SHA256 hash length {}", hash_length));
   432→
   433→    rc = EVP_DigestUpdate(md.get(), hash_buffer, hash_length);
   434→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   435→  }
   436→
   437→  for (const auto& hash : verify_certificate_hash_list_) {
   438→    rc = EVP_DigestUpdate(md.get(), hash.data(),
   439→                          hash.size() *
   440→                              sizeof(std::remove_reference<decltype(hash)>::type::value_type));
   441→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   442→  }
   443→
   444→  for (const auto& hash : verify_certificate_spki_list_) {
   445→    rc = EVP_DigestUpdate(md.get(), hash.data(),
   446→                          hash.size() *
   447→                              sizeof(std::remove_reference<decltype(hash)>::type::value_type));
   448→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   449→  }
   450→
   451→  rc = EVP_DigestUpdate(md.get(), &verify_trusted_ca_, sizeof(verify_trusted_ca_));
   452→  RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   453→
   454→  if (config_ != nullptr) {
   455→    for (const auto& matcher : config_->subjectAltNameMatchers()) {
   456→      size_t hash = MessageUtil::hash(matcher);
   457→      rc = EVP_DigestUpdate(md.get(), &hash, sizeof(hash));
   458→      RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   459→    }
   460→
   461→    const std::string& crl = config_->certificateRevocationList();
   462→    if (!crl.empty()) {
   463→      rc = EVP_DigestUpdate(md.get(), crl.data(), crl.length());
   464→      RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   465→    }
   466→
   467→    bool allow_expired = config_->allowExpiredCertificate();
   468→    rc = EVP_DigestUpdate(md.get(), &allow_expired, sizeof(allow_expired));
   469→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   470→
   471→    auto trust_chain_verification = config_->trustChainVerification();
   472→    rc = EVP_DigestUpdate(md.get(), &trust_chain_verification, sizeof(trust_chain_verification));
   473→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   474→
   475→    auto only_leaf_crl = config_->onlyVerifyLeafCertificateCrl();
   476→    rc = EVP_DigestUpdate(md.get(), &only_leaf_crl, sizeof(only_leaf_crl));
   477→    RELEASE_ASSERT(rc == 1, Utility::getLastCryptoError().value_or(""));
   478→  }
   479→}
   480→
   481→absl::Status DefaultCertValidator::addClientValidationContext(SSL_CTX* ctx,
   482→                                                              bool require_client_cert) {
   483→  if (config_ == nullptr || config_->caCert().empty()) {
   484→    return absl::OkStatus();
   485→  }
   486→
   487→  bssl::UniquePtr<BIO> bio(
   488→      BIO_new_mem_buf(const_cast<char*>(config_->caCert().data()), config_->caCert().size()));
   489→  RELEASE_ASSERT(bio != nullptr, "");
   490→  // Based on BoringSSL's SSL_add_file_cert_subjects_to_stack().
   491→  // Use a generic lambda to be compatible with BoringSSL before and after
   492→  // https://boringssl-review.googlesource.com/c/boringssl/+/56190
   493→  bssl::UniquePtr<STACK_OF(X509_NAME)> list(
   494→      sk_X509_NAME_new([](auto* a, auto* b) -> int { return X509_NAME_cmp(*a, *b); }));
   495→  RELEASE_ASSERT(list != nullptr, "");
   496→  for (;;) {
   497→    bssl::UniquePtr<X509> cert(PEM_read_bio_X509(bio.get(), nullptr, nullptr, nullptr));
   498→    if (cert == nullptr) {
   499→      break;
   500→    }
   501→    X509_NAME* name = X509_get_subject_name(cert.get());
   502→    if (name == nullptr) {
   503→      return absl::InvalidArgumentError(absl::StrCat(
   504→          "Failed to load trusted client CA certificates from ", config_->caCertPath()));
   505→    }
   506→    // Check for duplicates.
   507→    if (sk_X509_NAME_find(list.get(), nullptr, name)) {
   508→      continue;
   509→    }
   510→    bssl::UniquePtr<X509_NAME> name_dup(X509_NAME_dup(name));
   511→    if (name_dup == nullptr || !sk_X509_NAME_push(list.get(), name_dup.release())) {
   512→      return absl::InvalidArgumentError(absl::StrCat(
   513→          "Failed to load trusted client CA certificates from ", config_->caCertPath()));
   514→    }
   515→  }
   516→
   517→  // Check for EOF.
   518→  const uint32_t err = ERR_peek_last_error();
   519→  if (ERR_GET_LIB(err) == ERR_LIB_PEM && ERR_GET_REASON(err) == PEM_R_NO_START_LINE) {
   520→    ERR_clear_error();
   521→  } else {
   522→    return absl::InvalidArgumentError(
   523→        absl::StrCat("Failed to load trusted client CA certificates from ", config_->caCertPath()));
   524→  }
   525→  SSL_CTX_set_client_CA_list(ctx, list.release());
   526→
   527→  if (require_client_cert) {
   528→    SSL_CTX_set_verify(ctx, SSL_VERIFY_PEER | SSL_VERIFY_FAIL_IF_NO_PEER_CERT, nullptr);
   529→  }
   530→  // Set the verify_depth
   531→  if (config_->maxVerifyDepth().has_value()) {
   532→    uint32_t max_verify_depth = std::min(config_->maxVerifyDepth().value(), uint32_t{INT_MAX});
   533→#if BORINGSSL_API_VERSION >= 29
   534→    // Older BoringSSLs behave like OpenSSL 1.0.x and exclude the leaf from the
   535→    // depth but include the trust anchor. Newer BoringSSLs match OpenSSL 1.1.x
   536→    // and later in excluding both the leaf and trust anchor. `maxVerifyDepth`
   537→    // documents the older behavior, so adjust the value to match.
   538→    max_verify_depth = max_verify_depth > 0 ? max_verify_depth - 1 : 0;
   539→#endif
   540→    SSL_CTX_set_verify_depth(ctx, static_cast<int>(max_verify_depth));
   541→  }
   542→  return absl::OkStatus();
   543→}
   544→
   545→Envoy::Ssl::CertificateDetailsPtr DefaultCertValidator::getCaCertInformation() const {
   546→  if (ca_cert_ == nullptr) {
   547→    return nullptr;
   548→  }
